//! CONTEXT: Execd daemon entrypoint – wires host and OS-lite entrypoints into service loops
//! OWNERS: @runtime
//! STATUS: Functional
//! API_STABILITY: Unstable
//! TEST_COVERAGE: 8 unit tests (lib) + QEMU selftest markers
//! ADR: docs/adr/0007-executable-payloads-architecture.md

#[cfg(all(nexus_env = "os", target_arch = "riscv64", target_os = "none"))]
nexus_service_entry::declare_entry!(os_entry);

#[cfg(all(nexus_env = "os", target_arch = "riscv64", target_os = "none"))]
fn os_entry() -> execd::LiteResult<()> {
    // Minimal marker before any heap use (debugging bring-up).
    let _ = nexus_abi::debug_println("execd: entry");
    execd::service_main_loop(execd::ReadyNotifier::new(|| {}))
}

#[cfg(not(all(nexus_env = "os", target_arch = "riscv64", target_os = "none")))]
fn main() -> ! {
    execd::touch_schemas();
    if let Err(err) = execd::service_main_loop(execd::ReadyNotifier::new(|| ())) {
        eprintln!("execd: {err}");
    }
    loop {
        core::hint::spin_loop();
    }
}

